import { useState } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const presetBoxes = {

    front: {
      x: 50,
      y: 44,
      width: 430,
      height: 430
    },

    'left-chest': {
      x: 67,
      y: 29,
      width: 170,
      height: 170
    },

    back: {
      x: 50,
      y: 42,
      width: 520,
      height: 520
    }
  }

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [logoWidth, setLogoWidth] = useState(
    presetBoxes.front.width
  )

  const [logoHeight, setLogoHeight] = useState(
    presetBoxes.front.height
  )

  const [logoScale, setLogoScale] = useState(100)

  const [logoWarp, setLogoWarp] = useState(0)

  const [activePreset, setActivePreset] =
    useState('front')

  const autoFitLogo = (
    imageWidth,
    imageHeight,
    boxWidth,
    boxHeight
  ) => {

    const imageRatio =
      imageWidth / imageHeight

    const boxRatio =
      boxWidth / boxHeight

    let width
    let height

    if (imageRatio > boxRatio) {

      width = boxWidth
      height = boxWidth / imageRatio

    } else {

      height = boxHeight
      width = boxHeight * imageRatio
    }

    return {
      width,
      height
    }
  }

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    const img = new Image()

    img.onload = () => {

      const box =
        presetBoxes[activePreset]

      const fitted =
        autoFitLogo(
          img.width,
          img.height,
          box.width,
          box.height
        )

      setLogoWidth(fitted.width)

      setLogoHeight(fitted.height)

      setLogoScale(100)

      setUploadedLogo(imageUrl)
    }

    img.src = imageUrl
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (!uploadedLogo) return

    const img = new Image()

    img.onload = () => {

      const box =
        presetBoxes[type]

      const fitted =
        autoFitLogo(
          img.width,
          img.height,
          box.width,
          box.height
        )

      setLogoWidth(fitted.width)

      setLogoHeight(fitted.height)

      setLogoScale(100)
    }

    img.src = uploadedLogo
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const currentBox =
    presetBoxes[activePreset]

  return (

    <div className="h-screen bg-black text-white overflow-hidden">

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        <div className="bg-[#0a0a0a] flex items-center justify-center relative overflow-hidden">

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[1000px] scale-110"
          />

          {uploadedLogo && (

            <div
              className="absolute flex items-center justify-center overflow-hidden"
              style={{
                width: `${currentBox.width}px`,
                height: `${currentBox.height}px`,
                top: `${currentBox.y}%`,
                left: `${currentBox.x}%`,
                transform:
                  'translate(-50%, -50%)'
              }}
            >

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{
                  width: `${logoWidth}px`,
                  height: `${logoHeight}px`,
                  objectFit: 'contain',
                  transform: `
                    scale(${logoScale / 100})
                    perspective(900px)
                    rotateX(${logoWarp}deg)
                  `,
                  filter: `
                    contrast(1.03)
                    saturate(1.08)
                    brightness(1.02)
                  `
                }}
                draggable={false}
              />

            </div>

          )}

        </div>

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map((color) => (

                  <button
                    key={color.name}
                    onClick={() =>
                      setSelectedColor(color)
                    }
                    className={`p-4 rounded-xl text-xs font-black capitalize ${
                      selectedColor.name === color.name
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {color.name}
                  </button>

                ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setPreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {uploadedLogo && (

              <>
                <button
                  onClick={removeLogo}
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >

                  REMOVE LOGO

                </button>

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Zoom
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoScale}%
                    </p>

                  </div>

                  <input
                    type="range"
                    min="50"
                    max="180"
                    value={logoScale}
                    onChange={(e) =>
                      setLogoScale(e.target.value)
                    }
                    className="w-full"
                  />

                </div>

              </>

            )}

            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Fabric Warp
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {logoWarp}°
                </p>

              </div>

              <input
                type="range"
                min="-20"
                max="20"
                value={logoWarp}
                onChange={(e) =>
                  setLogoWarp(e.target.value)
                }
                className="w-full"
              />

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
